package org.example.service;

import org.example.model.GameState;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

@Service
public class CheckersGameService {

    // Board piece constants
    private static final int NONE      = 0;
    private static final int RED       = 1;
    private static final int RED_KING  = 2;
    private static final int BLACK     = 3;
    private static final int BLACK_KING = 4;

    private int[][] board;
    private String currentPlayer;   // "RED" or "BLACK"
    private String status;          // "PLAYING", "RED_WINS", "BLACK_WINS"
    private int selectedRow;
    private int selectedCol;
    private int[] multiJumpPiece;   // piece locked in a multi-jump chain
    private boolean forcedJumps = true; // when true, jumps are mandatory

    public CheckersGameService() {
        newGame();
    }

    // -------------------------------------------------------------------------
    // Public API
    // -------------------------------------------------------------------------

    public synchronized void setForcedJumps(boolean enabled) {
        this.forcedJumps = enabled;
        // Clear any selection so the player can re-evaluate their options
        selectedRow = -1;
        selectedCol = -1;
    }

    public synchronized void newGame() {
        board = new int[8][8];
        currentPlayer = "RED";
        status = "PLAYING";
        selectedRow = -1;
        selectedCol = -1;
        multiJumpPiece = null;
        initBoard();
    }

    public synchronized GameState getState() {
        GameState state = new GameState();

        int[][] boardCopy = new int[8][8];
        for (int i = 0; i < 8; i++) boardCopy[i] = board[i].clone();
        state.setBoard(boardCopy);

        state.setCurrentPlayer(currentPlayer);
        state.setStatus(status);
        state.setSelectedRow(selectedRow);
        state.setSelectedCol(selectedCol);
        state.setMultiJumpPiece(multiJumpPiece);
        state.setForcedJumps(forcedJumps);
        state.setRedCount(countPieces(true));
        state.setBlackCount(countPieces(false));

        if (selectedRow >= 0 && selectedCol >= 0) {
            state.setValidMoves(computeValidMoves(selectedRow, selectedCol));
        } else {
            state.setValidMoves(new ArrayList<>());
        }

        return state;
    }

    public synchronized GameState click(int row, int col) {
        if (!status.equals("PLAYING")) return getState();

        // ---- Multi-jump locked mode ----
        if (multiJumpPiece != null) {
            selectedRow = multiJumpPiece[0];
            selectedCol = multiJumpPiece[1];
            // Re-clicking the locked piece: just refresh view
            if (row == multiJumpPiece[0] && col == multiJumpPiece[1]) return getState();
            // Attempt the jump to (row, col)
            return executeMove(multiJumpPiece[0], multiJumpPiece[1], row, col);
        }

        int piece = board[row][col];

        // ---- Clicking on current player's own piece ----
        if (isOwnedBy(piece, currentPlayer)) {
            List<int[]> moves = computeValidMoves(row, col);
            if (!moves.isEmpty()) {
                selectedRow = row;
                selectedCol = col;
            }
            return getState();
        }

        // ---- Clicking on an empty square while a piece is selected ----
        if (piece == NONE && selectedRow >= 0 && selectedCol >= 0) {
            return executeMove(selectedRow, selectedCol, row, col);
        }

        // ---- Anything else: deselect ----
        selectedRow = -1;
        selectedCol = -1;
        return getState();
    }

    // -------------------------------------------------------------------------
    // Board initialisation
    // -------------------------------------------------------------------------

    private void initBoard() {
        for (int row = 0; row < 8; row++) {
            for (int col = 0; col < 8; col++) {
                if ((row + col) % 2 == 1) {
                    if (row < 3)      board[row][col] = BLACK;  // Black at top, moves down
                    else if (row > 4) board[row][col] = RED;    // Red at bottom, moves up
                }
            }
        }
    }

    // -------------------------------------------------------------------------
    // Move execution
    // -------------------------------------------------------------------------

    private GameState executeMove(int fromRow, int fromCol, int toRow, int toCol) {
        List<int[]> valid = computeValidMoves(fromRow, fromCol);
        boolean isValid = valid.stream().anyMatch(m -> m[0] == toRow && m[1] == toCol);
        if (!isValid) return getState();

        int piece = board[fromRow][fromCol];
        board[fromRow][fromCol] = NONE;
        board[toRow][toCol] = piece;

        boolean wasJump = Math.abs(toRow - fromRow) == 2;
        if (wasJump) {
            board[(fromRow + toRow) / 2][(fromCol + toCol) / 2] = NONE;
        }

        // King promotion
        boolean justKinged = false;
        if (piece == RED && toRow == 7) {
            board[toRow][toCol] = RED_KING;
            justKinged = true;
        } else if (piece == BLACK && toRow == 0) {
            board[toRow][toCol] = BLACK_KING;
            justKinged = true;
        }

        selectedRow = -1;
        selectedCol = -1;
        multiJumpPiece = null;

        // Check for multi-jump continuation (promotion ends the chain)
        if (wasJump && !justKinged && !jumpsForPiece(toRow, toCol).isEmpty()) {
            multiJumpPiece = new int[]{toRow, toCol};
            selectedRow = toRow;
            selectedCol = toCol;
            return getState();
        }

        // Switch turn
        currentPlayer = currentPlayer.equals("RED") ? "BLACK" : "RED";
        checkWinCondition();
        return getState();
    }

    // -------------------------------------------------------------------------
    // Valid move computation
    // -------------------------------------------------------------------------

    private List<int[]> computeValidMoves(int row, int col) {
        // During multi-jump, only the locked piece can move and only by jumping
        if (multiJumpPiece != null) {
            if (multiJumpPiece[0] == row && multiJumpPiece[1] == col) {
                return jumpsForPiece(row, col);
            }
            return new ArrayList<>();
        }

        int piece = board[row][col];
        if (!isOwnedBy(piece, currentPlayer)) return new ArrayList<>();

        // Forced-jump rule: if any current-player piece can jump, only jumps are allowed
        if (forcedJumps && playerHasJump(currentPlayer)) {
            return jumpsForPiece(row, col);
        }

        // No forced jumps — return all legal moves (simple steps + available jumps)
        List<int[]> all = new ArrayList<>(simpleMovesForPiece(row, col));
        all.addAll(jumpsForPiece(row, col));
        return all;
    }

    private List<int[]> jumpsForPiece(int row, int col) {
        List<int[]> jumps = new ArrayList<>();
        int piece = board[row][col];
        if (piece == NONE) return jumps;

        for (int rd : rowDirections(piece)) {
            for (int cd : new int[]{-1, 1}) {
                int midR = row + rd,   midC = col + cd;
                int endR = row + 2*rd, endC = col + 2*cd;
                if (inBounds(endR, endC)
                        && isOpponentOf(piece, board[midR][midC])
                        && board[endR][endC] == NONE) {
                    jumps.add(new int[]{endR, endC});
                }
            }
        }
        return jumps;
    }

    private List<int[]> simpleMovesForPiece(int row, int col) {
        List<int[]> moves = new ArrayList<>();
        int piece = board[row][col];
        if (piece == NONE) return moves;

        for (int rd : rowDirections(piece)) {
            for (int cd : new int[]{-1, 1}) {
                int nr = row + rd, nc = col + cd;
                if (inBounds(nr, nc) && board[nr][nc] == NONE) {
                    moves.add(new int[]{nr, nc});
                }
            }
        }
        return moves;
    }

    private boolean playerHasJump(String player) {
        for (int r = 0; r < 8; r++)
            for (int c = 0; c < 8; c++)
                if (isOwnedBy(board[r][c], player) && !jumpsForPiece(r, c).isEmpty())
                    return true;
        return false;
    }

    // -------------------------------------------------------------------------
    // Win condition
    // -------------------------------------------------------------------------

    private void checkWinCondition() {
        boolean hasMoves = false;
        int pieceCount = 0;

        outer:
        for (int r = 0; r < 8; r++) {
            for (int c = 0; c < 8; c++) {
                int p = board[r][c];
                if (!isOwnedBy(p, currentPlayer)) continue;
                pieceCount++;
                if (!hasMoves && (!jumpsForPiece(r, c).isEmpty() || !simpleMovesForPiece(r, c).isEmpty())) {
                    hasMoves = true;
                    break outer;
                }
            }
        }

        if (pieceCount == 0 || !hasMoves) {
            status = currentPlayer.equals("RED") ? "BLACK_WINS" : "RED_WINS";
        }
    }

    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    private int[] rowDirections(int piece) {
        return switch (piece) {
            case RED        -> new int[]{-1};        // Red moves up   (decreasing row)
            case BLACK      -> new int[]{1};         // Black moves down (increasing row)
            default         -> new int[]{-1, 1};     // Kings move both ways
        };
    }

    private boolean isOwnedBy(int piece, String player) {
        if (player.equals("RED"))   return piece == RED   || piece == RED_KING;
        if (player.equals("BLACK")) return piece == BLACK || piece == BLACK_KING;
        return false;
    }

    private boolean isOpponentOf(int forPiece, int other) {
        if (other == NONE) return false;
        boolean forIsRed = (forPiece == RED || forPiece == RED_KING);
        boolean otherIsRed = (other == RED || other == RED_KING);
        return forIsRed != otherIsRed;
    }

    private boolean inBounds(int r, int c) {
        return r >= 0 && r < 8 && c >= 0 && c < 8;
    }

    private int countPieces(boolean red) {
        int n = 0;
        for (int[] row : board)
            for (int p : row)
                if (red ? (p == RED || p == RED_KING) : (p == BLACK || p == BLACK_KING)) n++;
        return n;
    }
}

package org.example.service;

import org.example.model.GameState;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

@Service
public class CheckersGameService {

    // Board piece constants
    private static final int NONE      = 0;
    private static final int RED       = 1;
    private static final int RED_KING  = 2;
    private static final int BLACK     = 3;
    private static final int BLACK_KING = 4;

    private int[][] board;
    private String currentPlayer;   // "RED" or "BLACK"
    private String status;          // "PLAYING", "RED_WINS", "BLACK_WINS"
    private int selectedRow;
    private int selectedCol;
    private int[] multiJumpPiece;   // piece locked in a multi-jump chain
    private boolean forcedJumps = true; // when true, jumps are mandatory

    public CheckersGameService() {
        newGame();
    }

    // -------------------------------------------------------------------------
    // Public API
    // -------------------------------------------------------------------------

    public synchronized void setForcedJumps(boolean enabled) {
        this.forcedJumps = enabled;
        // Clear any selection so the player can re-evaluate their options
        selectedRow = -1;
        selectedCol = -1;
    }

    public synchronized void newGame() {
        board = new int[8][8];
        currentPlayer = "RED";
        status = "PLAYING";
        selectedRow = -1;
        selectedCol = -1;
        multiJumpPiece = null;
        initBoard();
    }

    public synchronized GameState getState() {
        GameState state = new GameState();

        int[][] boardCopy = new int[8][8];
        for (int i = 0; i < 8; i++) boardCopy[i] = board[i].clone();
        state.setBoard(boardCopy);

        state.setCurrentPlayer(currentPlayer);
        state.setStatus(status);
        state.setSelectedRow(selectedRow);
        state.setSelectedCol(selectedCol);
        state.setMultiJumpPiece(multiJumpPiece);
        state.setForcedJumps(forcedJumps);
        state.setRedCount(countPieces(true));
        state.setBlackCount(countPieces(false));

        if (selectedRow >= 0 && selectedCol >= 0) {
            state.setValidMoves(computeValidMoves(selectedRow, selectedCol));
        } else {
            state.setValidMoves(new ArrayList<>());
        }

        return state;
    }

    public synchronized GameState click(int row, int col) {
        if (!status.equals("PLAYING")) return getState();

        // ---- Multi-jump locked mode ----
        if (multiJumpPiece != null) {
            selectedRow = multiJumpPiece[0];
            selectedCol = multiJumpPiece[1];
            // Re-clicking the locked piece: just refresh view
            if (row == multiJumpPiece[0] && col == multiJumpPiece[1]) return getState();
            // Attempt the jump to (row, col)
            return executeMove(multiJumpPiece[0], multiJumpPiece[1], row, col);
        }

        int piece = board[row][col];

        // ---- Clicking on current player's own piece ----
        if (isOwnedBy(piece, currentPlayer)) {
            List<int[]> moves = computeValidMoves(row, col);
            if (!moves.isEmpty()) {
                selectedRow = row;
                selectedCol = col;
            }
            return getState();
        }

        // ---- Clicking on an empty square while a piece is selected ----
        if (piece == NONE && selectedRow >= 0 && selectedCol >= 0) {
            return executeMove(selectedRow, selectedCol, row, col);
        }

        // ---- Anything else: deselect ----
        selectedRow = -1;
        selectedCol = -1;
        return getState();
    }

    // -------------------------------------------------------------------------
    // Board initialisation
    // -------------------------------------------------------------------------

    private void initBoard() {
        for (int row = 0; row < 8; row++) {
            for (int col = 0; col < 8; col++) {
                if ((row + col) % 2 == 1) {
                    if (row < 3)      board[row][col] = BLACK;  // Black at top, moves down
                    else if (row > 4) board[row][col] = RED;    // Red at bottom, moves up
                }
            }
        }
    }

    // -------------------------------------------------------------------------
    // Move execution
    // -------------------------------------------------------------------------

    private GameState executeMove(int fromRow, int fromCol, int toRow, int toCol) {
        List<int[]> valid = computeValidMoves(fromRow, fromCol);
        boolean isValid = valid.stream().anyMatch(m -> m[0] == toRow && m[1] == toCol);
        if (!isValid) return getState();

        int piece = board[fromRow][fromCol];
        board[fromRow][fromCol] = NONE;
        board[toRow][toCol] = piece;

        boolean wasJump = Math.abs(toRow - fromRow) == 2;
        if (wasJump) {
            board[(fromRow + toRow) / 2][(fromCol + toCol) / 2] = NONE;
        }

        // King promotion
        boolean justKinged = false;
        if (piece == RED && toRow == 7) {
            board[toRow][toCol] = RED_KING;
            justKinged = true;
        } else if (piece == BLACK && toRow == 0) {
            board[toRow][toCol] = BLACK_KING;
            justKinged = true;
        }

        selectedRow = -1;
        selectedCol = -1;
        multiJumpPiece = null;

        // Check for multi-jump continuation (promotion ends the chain)
        if (wasJump && !justKinged && !jumpsForPiece(toRow, toCol).isEmpty()) {
            multiJumpPiece = new int[]{toRow, toCol};
            selectedRow = toRow;
            selectedCol = toCol;
            return getState();
        }

        // Switch turn
        currentPlayer = currentPlayer.equals("RED") ? "BLACK" : "RED";
        checkWinCondition();
        return getState();
    }

    // -------------------------------------------------------------------------
    // Valid move computation
    // -------------------------------------------------------------------------

    private List<int[]> computeValidMoves(int row, int col) {
        // During multi-jump, only the locked piece can move and only by jumping
        if (multiJumpPiece != null) {
            if (multiJumpPiece[0] == row && multiJumpPiece[1] == col) {
                return jumpsForPiece(row, col);
            }
            return new ArrayList<>();
        }

        int piece = board[row][col];
        if (!isOwnedBy(piece, currentPlayer)) return new ArrayList<>();

        // Forced-jump rule: if any current-player piece can jump, only jumps are allowed
        if (forcedJumps && playerHasJump(currentPlayer)) {
            return jumpsForPiece(row, col);
        }

        // No forced jumps — return all legal moves (simple steps + available jumps)
        List<int[]> all = new ArrayList<>(simpleMovesForPiece(row, col));
        all.addAll(jumpsForPiece(row, col));
        return all;
    }

    private List<int[]> jumpsForPiece(int row, int col) {
        List<int[]> jumps = new ArrayList<>();
        int piece = board[row][col];
        if (piece == NONE) return jumps;

        for (int rd : rowDirections(piece)) {
            for (int cd : new int[]{-1, 1}) {
                int midR = row + rd,   midC = col + cd;
                int endR = row + 2*rd, endC = col + 2*cd;
                if (inBounds(endR, endC)
                        && isOpponentOf(piece, board[midR][midC])
                        && board[endR][endC] == NONE) {
                    jumps.add(new int[]{endR, endC});
                }
            }
        }
        return jumps;
    }

    private List<int[]> simpleMovesForPiece(int row, int col) {
        List<int[]> moves = new ArrayList<>();
        int piece = board[row][col];
        if (piece == NONE) return moves;

        for (int rd : rowDirections(piece)) {
            for (int cd : new int[]{-1, 1}) {
                int nr = row + rd, nc = col + cd;
                if (inBounds(nr, nc) && board[nr][nc] == NONE) {
                    moves.add(new int[]{nr, nc});
                }
            }
        }
        return moves;
    }

    private boolean playerHasJump(String player) {
        for (int r = 0; r < 8; r++)
            for (int c = 0; c < 8; c++)
                if (isOwnedBy(board[r][c], player) && !jumpsForPiece(r, c).isEmpty())
                    return true;
        return false;
    }

    // -------------------------------------------------------------------------
    // Win condition
    // -------------------------------------------------------------------------

    private void checkWinCondition() {
        // A player loses only when they have no pieces remaining
        if (countPieces(true) == 0) {
            status = "BLACK_WINS";
        } else if (countPieces(false) == 0) {
            status = "RED_WINS";
        }
    }

    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    private int[] rowDirections(int piece) {
        return switch (piece) {
            case RED        -> new int[]{-1};        // Red moves up   (decreasing row)
            case BLACK      -> new int[]{1};         // Black moves down (increasing row)
            default         -> new int[]{-1, 1};     // Kings move both ways
        };
    }

    private boolean isOwnedBy(int piece, String player) {
        if (player.equals("RED"))   return piece == RED   || piece == RED_KING;
        if (player.equals("BLACK")) return piece == BLACK || piece == BLACK_KING;
        return false;
    }

    private boolean isOpponentOf(int forPiece, int other) {
        if (other == NONE) return false;
        boolean forIsRed = (forPiece == RED || forPiece == RED_KING);
        boolean otherIsRed = (other == RED || other == RED_KING);
        return forIsRed != otherIsRed;
    }

    private boolean inBounds(int r, int c) {
        return r >= 0 && r < 8 && c >= 0 && c < 8;
    }

    private int countPieces(boolean red) {
        int n = 0;
        for (int[] row : board)
            for (int p : row)
                if (red ? (p == RED || p == RED_KING) : (p == BLACK || p == BLACK_KING)) n++;
        return n;
    }
}
